SET SQL_MODE = 'NO_AUTO_VALUE_ON_ZERO';
SET FOREIGN_KEY_CHECKS = 0;
SET NAMES utf8mb4;

CREATE TABLE analisis_avanzado (
	id INTEGER NOT NULL, 
	animal_id INTEGER NOT NULL, 
	tipo_analisis VARCHAR(100) NOT NULL, 
	parametros VARCHAR(500), 
	resultados VARCHAR(1000), 
	fecha_analisis DATETIME, 
	recomendaciones VARCHAR(500), 
	puntaje FLOAT, 
	PRIMARY KEY (id), 
	FOREIGN KEY(animal_id) REFERENCES ganado (id)
);
CREATE TABLE categoria_insumo (
	id INTEGER NOT NULL, 
	nombre VARCHAR(100) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (nombre)
);
CREATE TABLE error_log (
	id INTEGER NOT NULL, 
	mensaje VARCHAR(500) NOT NULL, 
	zona VARCHAR(100) NOT NULL, 
	detalles TEXT, 
	fecha DATETIME, 
	usuario VARCHAR(50), 
	PRIMARY KEY (id)
);
CREATE TABLE especie (
	id INTEGER NOT NULL, 
	nombre VARCHAR(100) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (nombre)
);
CREATE TABLE estado_animal (
	id INTEGER NOT NULL, 
	nombre VARCHAR(50) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (nombre)
);
CREATE TABLE estado_protocolo (
	id INTEGER NOT NULL, 
	nombre VARCHAR(50) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (nombre)
);
CREATE TABLE expediente_medico (
	id INTEGER NOT NULL, 
	animal_id INTEGER NOT NULL, 
	tipo_sangre VARCHAR(10), 
	alergias VARCHAR(500), 
	condiciones_cronicas VARCHAR(500), 
	antecedentes_geneticos VARCHAR(500), 
	notas_generales VARCHAR(1000), 
	fecha_creacion DATETIME, 
	ultima_actualizacion DATETIME, 
	PRIMARY KEY (id), 
	UNIQUE (animal_id), 
	FOREIGN KEY(animal_id) REFERENCES ganado (id)
);
CREATE TABLE ganado (
	id INTEGER NOT NULL, 
	especie_id INTEGER NOT NULL, 
	raza_id INTEGER NOT NULL, 
	sexo_id INTEGER NOT NULL, 
	fecha_nacimiento VARCHAR(10) NOT NULL, 
	edad INTEGER NOT NULL, 
	peso FLOAT NOT NULL, 
	estado_id INTEGER, 
	padre_id INTEGER, 
	madre_id INTEGER, 
	PRIMARY KEY (id), 
	FOREIGN KEY(especie_id) REFERENCES especie (id) ON DELETE RESTRICT, 
	FOREIGN KEY(raza_id) REFERENCES raza (id) ON DELETE RESTRICT, 
	FOREIGN KEY(sexo_id) REFERENCES sexo (id), 
	FOREIGN KEY(estado_id) REFERENCES estado_animal (id), 
	FOREIGN KEY(padre_id) REFERENCES ganado (id) ON DELETE SET NULL, 
	FOREIGN KEY(madre_id) REFERENCES ganado (id) ON DELETE SET NULL
);
CREATE TABLE historial_cambios (
        id INTEGER NOT NULL, 
        animal_id INTEGER, 
        campo VARCHAR(50) NOT NULL, 
        valor_anterior VARCHAR(100), 
        valor_nuevo VARCHAR(100) NOT NULL, 
        fecha_cambio DATETIME, 
        usuario VARCHAR(50), 
        accion VARCHAR(20), 
        PRIMARY KEY (id), 
        FOREIGN KEY(animal_id) REFERENCES ganado (id)
    );
CREATE TABLE historial_insumo (
	id INTEGER NOT NULL, 
	insumo_id INTEGER NOT NULL, 
	tipo_movimiento VARCHAR(50) NOT NULL, 
	cantidad_cambio VARCHAR(100) NOT NULL, 
	stock_nuevo FLOAT, 
	fecha DATETIME, 
	usuario VARCHAR(50), 
	PRIMARY KEY (id), 
	FOREIGN KEY(insumo_id) REFERENCES insumo (id)
);
CREATE TABLE historial_medico (
	id INTEGER NOT NULL, 
	animal_id INTEGER NOT NULL, 
	tipo_id INTEGER NOT NULL, 
	descripcion VARCHAR(200) NOT NULL, 
	fecha DATETIME, 
	veterinario_id INTEGER, 
	PRIMARY KEY (id), 
	FOREIGN KEY(animal_id) REFERENCES ganado (id), 
	FOREIGN KEY(tipo_id) REFERENCES tipo_evento_medico (id), 
	FOREIGN KEY(veterinario_id) REFERENCES usuario (id)
);
CREATE TABLE insumo (
	id INTEGER NOT NULL, 
	nombre VARCHAR(100) NOT NULL, 
	categoria_id INTEGER NOT NULL, 
	cantidad FLOAT, 
	unidad_id INTEGER NOT NULL, 
	stock_minimo FLOAT, 
	fecha_vencimiento DATE, 
	ubicacion VARCHAR(100), 
	nota VARCHAR(200), 
	PRIMARY KEY (id), 
	FOREIGN KEY(categoria_id) REFERENCES categoria_insumo (id), 
	FOREIGN KEY(unidad_id) REFERENCES unidad_medida (id)
);
CREATE TABLE notificacion_descartada (
	id INTEGER NOT NULL, 
