	activo BOOLEAN, 
	observaciones VARCHAR(500), 
	agua VARCHAR(100), 
	frecuencia VARCHAR(100), 
	suplementos VARCHAR(500), usuario VARCHAR(50) DEFAULT 'admin', 
	PRIMARY KEY (id), 
	FOREIGN KEY(animal_id) REFERENCES ganado (id) ON DELETE CASCADE, 
	FOREIGN KEY(tipo_alimentacion_id) REFERENCES tipo_alimentacion (id)
);
CREATE TABLE prediccion_productividad (
